export default async function ({ execution_id }) {
  const response = await fetch('/platform/automation/v1/executions/' + execution_id + '/tasks/perform-action/result');
  const body = await response.json();

  await new Promise((resolve) => setTimeout(resolve, 1500));

  const status = (
    body?.AutomationExecution?.AutomationExecutionStatus ||
    body?.AutomationExecutionStatus ||
    body?.properties?.status ||
    body?.status ||
    body?.state ||
    body?.executionStatus ||
    body?.result?.executionStatus ||
    body?.jobStatus ||
    ''
  ).toString().toUpperCase();

  const inProgress = ['INPROGRESS','PENDING','RUNNING','NEW','ACTIVATING','QUEUED','STARTING'];
  if (inProgress.includes(status)) {
    throw new Error('Action still running: ' + status);
  }

  return { status, body };
}

export default async function ({ execution_id }) {
  const response = await fetch('/platform/automation/v1/executions/' + execution_id + '/tasks/wait-for-action/result');
  const payload = await response.json();
  const status = (payload?.status || '').toString().toUpperCase();

  const failed = ['FAILED','FAILURE','ERROR','TIMED_OUT','CANCELLED','STOPPED','BLOCKED'];
  if (failed.includes(status)) {
    throw new Error('Action reported failure status: ' + status);
  }

  if (!payload || !payload.body) {
    throw new Error('Action result payload is empty');
  }

  return payload.body;
}
